"use client";

import {
  useDeferredValue,
  useEffect,
  useMemo,
  useRef,
} from "react";
import type { Extension } from "@codemirror/state";
import { TooltipProvider } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";

import { useCodeMirror } from "./hooks/use-codemirror";
import { useViewMode } from "./hooks/use-view-mode";
import {
  useToolbarStore,
  useToolbarVersion,
} from "./hooks/use-toolbar-state";
import { useMarkdownEditorHandle } from "./hooks/use-imperative-handle";
import { Toolbar } from "./parts/toolbar";
import { ViewToggle } from "./parts/view-toggle";
import { EditorPane } from "./parts/editor-pane";
import { PreviewPane } from "./parts/preview-pane";
import { defaultMarkdownToolbar } from "./default-toolbar";
import { parseMarkdown } from "./lib/parse-markdown";
import {
  insertText as insertTextAction,
  toggleLinePrefix as toggleLinePrefixAction,
  wrapSelection as wrapSelectionAction,
} from "./lib/toolbar-actions";
import type {
  KindMeta,
  MarkdownEditorProps,
  ToolbarCtx,
  WikilinkCandidate,
} from "./types";

const EMPTY_EXTENSIONS: ReadonlyArray<Extension> = [];

export function MarkdownEditor<TCandidate extends WikilinkCandidate = WikilinkCandidate>(
  props: MarkdownEditorProps<TCandidate>,
) {
  const {
    value,
    onChange,
    readOnly = false,
    view: viewProp,
    onViewChange,
    initialView = "edit",
    showPreviewToggle = true,
    wikilinkCandidates,
    onWikilinkClick,
    kinds,
    toolbar,
    extensions,
    onSave,
    ariaLabel,
    className,
    minHeight,
    maxHeight,
    ref,
    id,
  } = props;

  // Stable refs holding latest callbacks (post-commit update — read by CM6 extensions
  // captured at mount time so prop changes flow through without reconfiguring the stack).
  const onChangeRef = useRef(onChange);
  const onSaveRef = useRef<typeof onSave>(onSave);
  const kindsRef = useRef<Record<string, KindMeta> | undefined>(kinds);
  const onWikilinkClickRef = useRef<typeof onWikilinkClick>(onWikilinkClick);

  useEffect(() => {
    onChangeRef.current = onChange;
    onSaveRef.current = onSave;
    kindsRef.current = kinds;
    onWikilinkClickRef.current = onWikilinkClick;
  });

  // Toolbar external store — bumped by CM6 update listener on selection or doc changes.
  const toolbarStore = useToolbarStore();
  const onRelevantUpdateRef = useRef<(() => void) | undefined>(toolbarStore.notify);
  useEffect(() => {
    onRelevantUpdateRef.current = toolbarStore.notify;
  }, [toolbarStore]);

  const userExtensions = extensions ?? EMPTY_EXTENSIONS;

  const { view, setContainer } = useCodeMirror({
    value,
    readOnly,
    wikilinkCandidates,
    userExtensions,
    onChangeRef,
    onSaveRef,
    kindsRef,
    onRelevantUpdateRef,
    ariaLabel,
  });

  const { viewValue, handleViewChange, toggleHidden } = useViewMode({
    view: viewProp,
    onViewChange,
    initialView,
    showPreviewToggle,
  });

  // Subscribe to toolbar updates — re-renders toolbar buttons on selection/doc changes.
  useToolbarVersion(toolbarStore);

  // Preview HTML — useDeferredValue keeps typing fluid; parse runs at low priority.
  const deferredValue = useDeferredValue(value);
  const hasClickHandler = Boolean(onWikilinkClick);
  const html = useMemo(
    () =>
      parseMarkdown(deferredValue, {
        wikilinkCandidates,
        kinds,
        hasClickHandler,
      }),
    [deferredValue, wikilinkCandidates, kinds, hasClickHandler],
  );

  // Build ToolbarCtx from current view — recomputed on render (cheap; closures over view).
  const ctx: ToolbarCtx | null = view
    ? {
        view,
        value: view.state.doc.toString(),
        insertText: (text) => insertTextAction(view, text),
        wrapSelection: (before, after) => wrapSelectionAction(view, before, after),
        toggleLinePrefix: (prefix) => toggleLinePrefixAction(view, prefix),
      }
    : null;

  const showToolbar = toolbar !== false;
  const items = toolbar === undefined || toolbar === false ? defaultMarkdownToolbar : toolbar;
  const showEditor = viewValue !== "preview";
  const showPreview = viewValue !== "edit";

  // Imperative handle wiring (Q-P10 ref-as-prop pattern).
  useMarkdownEditorHandle({ ref, view });

  // Onclick handler for preview wikilinks reads onWikilinkClickRef so prop changes
  // flow through without re-binding the stable click delegation.
  const handlePreviewWikilinkClick = useMemo(
    () => (target: string) => {
      onWikilinkClickRef.current?.(target);
    },
    [],
  );

  return (
    <TooltipProvider>
      <div
        id={id}
        role="group"
        aria-label={ariaLabel ?? "Markdown editor"}
        className={cn("markdown-editor flex flex-col", className)}
      >
        {(showToolbar || !toggleHidden) && (
          <div
            className={cn(
              "flex flex-wrap items-center justify-between gap-2",
              showToolbar
                ? "rounded-t-md border border-b-0 border-border bg-card px-2 py-1.5"
                : null,
            )}
          >
            {showToolbar && ctx ? (
              <Toolbar
                items={items}
                ctx={ctx}
                disabled={readOnly || viewValue === "preview"}
                className="border-0 bg-transparent p-0"
              />
            ) : showToolbar ? (
              // Pre-mount placeholder so layout doesn't shift when CM6 attaches.
              <div className="h-7" aria-hidden />
            ) : null}
            {!toggleHidden && (
              <ViewToggle value={viewValue} onChange={handleViewChange} />
            )}
          </div>
        )}

        <div
          className={cn(
            "@container flex min-h-0 overflow-hidden rounded-b-md border border-border",
            !showToolbar && toggleHidden && "rounded-t-md",
            viewValue === "split"
              ? "flex-col @[480px]:flex-row @[480px]:gap-0"
              : "flex-col",
          )}
        >
          {showEditor && (
            <EditorPane
              setContainer={setContainer}
              minHeight={minHeight}
              maxHeight={maxHeight}
              className={cn(
                viewValue === "split" && "@[480px]:border-r @[480px]:border-border",
              )}
            />
          )}
          {showPreview && (
            <PreviewPane
              html={html}
              onWikilinkClick={hasClickHandler ? handlePreviewWikilinkClick : undefined}
              minHeight={minHeight}
              maxHeight={maxHeight}
            />
          )}
        </div>
      </div>
    </TooltipProvider>
  );
}

export { MarkdownEditor } from "./markdown-editor";
export { defaultMarkdownToolbar } from "./default-toolbar";
export { parseMarkdown } from "./lib/parse-markdown";
export type {
  KindMeta,
  MarkdownEditorHandle,
  MarkdownEditorProps,
  ToolbarCtx,
  ToolbarItem,
  ViewMode,
  WikilinkCandidate,
} from "./types";
export { meta } from "./meta";

import type { ReactNode, Ref } from "react";
import type { Extension } from "@codemirror/state";
import type { EditorView } from "@codemirror/view";

export interface WikilinkCandidate {
  id: string;
  label: string;
  kind?: string;
  alias?: string;
}

export interface KindMeta {
  label: string;
  color?: string;
}

export type ViewMode = "edit" | "preview" | "split";

export interface ToolbarCtx {
  view: EditorView;
  value: string;
  insertText: (text: string) => void;
  wrapSelection: (before: string, after?: string) => void;
  toggleLinePrefix: (prefix: string) => void;
}

export interface ToolbarItem {
  id: string;
  label: string;
  icon?: ReactNode;
  shortcut?: string;
  isActive?: (ctx: ToolbarCtx) => boolean;
  run: (ctx: ToolbarCtx) => void;
}

export interface MarkdownEditorProps<TCandidate extends WikilinkCandidate = WikilinkCandidate> {
  value: string;
  onChange: (value: string) => void;
  readOnly?: boolean;

  view?: ViewMode;
  onViewChange?: (view: ViewMode) => void;
  initialView?: ViewMode;
  showPreviewToggle?: boolean;

  wikilinkCandidates?: ReadonlyArray<TCandidate>;
  onWikilinkClick?: (target: string) => void;
  kinds?: Record<string, KindMeta>;

  toolbar?: false | ReadonlyArray<ToolbarItem>;

  extensions?: ReadonlyArray<Extension>;

  onSave?: (value: string) => void;

  ariaLabel?: string;
  className?: string;
  placeholder?: string;
  minHeight?: string | number;
  maxHeight?: string | number;

  ref?: Ref<MarkdownEditorHandle>;

  id?: string;
}

export interface MarkdownEditorHandle {
  focus(): void;
  undo(): void;
  redo(): void;
  insertText(text: string): void;
  getSelection(): { from: number; to: number; text: string };
  getValue(): string;
  getView(): EditorView | null;
}

import { Bold, Code, Heading, Italic, Link, List, ListOrdered, Quote } from "lucide-react";
import { cycleHeading, isInlineMarkActive } from "./lib/toolbar-actions";
import type { ToolbarItem } from "./types";

// Default markdown toolbar — 8 built-in items + 1 separator between link and lists (Q-P4 + §13.5 #7).
// Hosts spread + extend per description §6.2.
export const defaultMarkdownToolbar: ReadonlyArray<ToolbarItem> = [
  {
    id: "bold",
    label: "Bold",
    icon: <Bold />,
    shortcut: "⌘B",
    isActive: (ctx) => isInlineMarkActive(ctx.view, "**"),
    run: (ctx) => ctx.wrapSelection("**", "**"),
  },
  {
    id: "italic",
    label: "Italic",
    icon: <Italic />,
    shortcut: "⌘I",
    run: (ctx) => ctx.wrapSelection("*", "*"),
  },
  {
    id: "code",
    label: "Inline code",
    icon: <Code />,
    shortcut: "⌘E",
    isActive: (ctx) => isInlineMarkActive(ctx.view, "`"),
    run: (ctx) => ctx.wrapSelection("`", "`"),
  },
  {
    id: "link",
    label: "Link",
    icon: <Link />,
    shortcut: "⌘K",
    run: (ctx) => {
      const { from, to } = ctx.view.state.selection.main;
      const selectedText = ctx.view.state.sliceDoc(from, to);
      const before = `[${selectedText}](`;
      const placeholder = "url";
      const after = ")";
      const insertStart = from + before.length;
      ctx.view.dispatch({
        changes: { from, to, insert: `${before}${placeholder}${after}` },
        selection: { anchor: insertStart, head: insertStart + placeholder.length },
      });
      ctx.view.focus();
    },
  },
  { id: "sep-1", label: "", run: () => {} },
  {
    id: "bullet-list",
    label: "Bullet list",
    icon: <List />,
    run: (ctx) => ctx.toggleLinePrefix("- "),
  },
  {
    id: "numbered-list",
    label: "Numbered list",
    icon: <ListOrdered />,
    run: (ctx) => ctx.toggleLinePrefix("1. "),
  },
  {
    id: "blockquote",
    label: "Blockquote",
    icon: <Quote />,
    run: (ctx) => ctx.toggleLinePrefix("> "),
  },
  {
    id: "heading",
    label: "Heading",
    icon: <Heading />,
    run: (ctx) => cycleHeading(ctx.view),
  },
];

import { useEffect, useRef, useState } from "react";
import { EditorState, type Extension } from "@codemirror/state";
import {
  EditorView,
  drawSelection,
  highlightActiveLine,
  keymap,
} from "@codemirror/view";
import { defaultKeymap, history, historyKeymap, indentWithTab } from "@codemirror/commands";
import { search, searchKeymap, highlightSelectionMatches } from "@codemirror/search";
import {
  autocompletion,
  closeBrackets,
  closeBracketsKeymap,
  completionKeymap,
} from "@codemirror/autocomplete";
import { markdown, markdownLanguage } from "@codemirror/lang-markdown";
import { GFM } from "@lezer/markdown";

import { markdownEditorTheme } from "../lib/extensions/theme";
import {
  buildCandidatesMap,
  setCandidatesEffect,
  wikilinkExtension,
} from "../lib/extensions/wikilink";
import { createWikilinkCompletionSource } from "../lib/extensions/wikilink-autocomplete";
import { saveKeymap } from "../lib/extensions/save-keymap";
import { markdownKeymap } from "../lib/extensions/markdown-keymap";
import { readOnlyCompartment, userExtensionsCompartment } from "../lib/extensions/compartments";
import { SyncAnnotation } from "../lib/sync-annotation";
import type { KindMeta, WikilinkCandidate } from "../types";
import type { RefObject } from "react";

interface UseCodeMirrorOpts {
  value: string;
  readOnly: boolean;
  wikilinkCandidates: ReadonlyArray<WikilinkCandidate> | undefined;
  userExtensions: ReadonlyArray<Extension>;
  onChangeRef: RefObject<(value: string) => void>;
  onSaveRef: RefObject<((value: string) => void) | undefined>;
  kindsRef: RefObject<Record<string, KindMeta> | undefined>;
  // Notified on selection-set or doc-change CM6 updates so dependent surfaces
  // (toolbar active state) can re-render without reconfiguring extensions.
  onRelevantUpdateRef: RefObject<(() => void) | undefined>;
  ariaLabel: string | undefined;
}

interface UseCodeMirrorResult {
  // React-state view — null until CM6 mounts; safe to read during render.
  view: EditorView | null;
  setContainer: (node: HTMLDivElement | null) => void;
}

export function useCodeMirror(opts: UseCodeMirrorOpts): UseCodeMirrorResult {
  const {
    value,
    readOnly,
    wikilinkCandidates,
    userExtensions,
    onChangeRef,
    onSaveRef,
    kindsRef,
    onRelevantUpdateRef,
    ariaLabel,
  } = opts;

  const [view, setView] = useState<EditorView | null>(null);
  const lastSyncedValueRef = useRef<string>(value);
  const [container, setContainer] = useState<HTMLDivElement | null>(null);

  // Mount-time prop snapshot via refs — read by mount effect; updated post-commit so
  // the snapshot stays fresh if a parent re-renders between hook call and mount.
  const valueAtMountRef = useRef(value);
  const readOnlyAtMountRef = useRef(readOnly);
  const candidatesAtMountRef = useRef(wikilinkCandidates);
  const userExtensionsAtMountRef = useRef(userExtensions);
  const ariaLabelAtMountRef = useRef(ariaLabel);

  useEffect(() => {
    valueAtMountRef.current = value;
    readOnlyAtMountRef.current = readOnly;
    candidatesAtMountRef.current = wikilinkCandidates;
    userExtensionsAtMountRef.current = userExtensions;
    ariaLabelAtMountRef.current = ariaLabel;
  });

  // Mount effect — keyed only on container; subsequent prop changes flow through
  // the sync effects below. Mount-time prop reads come from the refs above.
  useEffect(() => {
    if (!container) return;

    const initialDoc = valueAtMountRef.current;
    const initialReadOnly = readOnlyAtMountRef.current;
    const initialCandidates = candidatesAtMountRef.current;
    const initialUserExtensions = userExtensionsAtMountRef.current;
    const initialAriaLabel = ariaLabelAtMountRef.current;

    const extensions: Extension[] = [
      EditorView.lineWrapping,
      EditorState.tabSize.of(2),
      drawSelection(),
      highlightActiveLine(),
      highlightSelectionMatches(),
      closeBrackets(),

      markdown({ base: markdownLanguage, extensions: [GFM], addKeymap: true }),

      history(),
      search({ top: true }),

      ...wikilinkExtension,

      autocompletion({
        override: [createWikilinkCompletionSource(kindsRef)],
      }),

      markdownEditorTheme,

      // Keymap — most-specific first; each binding's `run: () => true` stops further keymaps.
      keymap.of([
        ...saveKeymap(onSaveRef),
        ...markdownKeymap(),
        ...closeBracketsKeymap,
        ...defaultKeymap,
        ...historyKeymap,
        ...searchKeymap,
        ...completionKeymap,
        indentWithTab,
      ]),

      readOnlyCompartment.of(EditorState.readOnly.of(initialReadOnly)),

      // Echo-guard updateListener (Q-P9) — skip onChange when transaction carries SyncAnnotation.
      EditorView.updateListener.of((update) => {
        if (
          update.docChanged &&
          !update.transactions.some((t) => t.annotation(SyncAnnotation))
        ) {
          onChangeRef.current(update.state.doc.toString());
        }
        if (update.selectionSet || update.docChanged) {
          onRelevantUpdateRef.current?.();
        }
      }),

      EditorView.contentAttributes.of(
        initialAriaLabel ? { "aria-label": initialAriaLabel } : {},
      ),

      // User extensions LAST — earlier-in-array = HIGHER CM6 default precedence (Q-P8 lock).
      // Our defaults win conflicts; users escalate via Prec.high(...).
      userExtensionsCompartment.of([...initialUserExtensions]),
    ];

    const editorView = new EditorView({
      state: EditorState.create({ doc: initialDoc, extensions }),
      parent: container,
    });

    // Seed initial candidates via dispatch (StateField starts empty).
    if (initialCandidates && initialCandidates.length > 0) {
      editorView.dispatch({
        effects: setCandidatesEffect.of(buildCandidatesMap(initialCandidates)),
      });
    }

    setView(editorView);
    lastSyncedValueRef.current = initialDoc;

    return () => {
      editorView.destroy();
      setView(null);
    };
    // Mount only on container change. All prop changes flow through sync effects below.
  }, [container, kindsRef, onChangeRef, onSaveRef, onRelevantUpdateRef]);

  // Value sync (Q-P9 echo-guarded).
  useEffect(() => {
    if (!view) return;
    if (
      value !== lastSyncedValueRef.current &&
      value !== view.state.doc.toString()
    ) {
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: value },
        annotations: SyncAnnotation.of(true),
      });
    }
    lastSyncedValueRef.current = value;
  }, [view, value]);

  // ReadOnly sync.
  useEffect(() => {
    view?.dispatch({
      effects: readOnlyCompartment.reconfigure(EditorState.readOnly.of(readOnly)),
    });
  }, [view, readOnly]);

  // wikilinkCandidates sync (validate-pass refinement #2).
  useEffect(() => {
    if (!view) return;
    view.dispatch({
      effects: setCandidatesEffect.of(buildCandidatesMap(wikilinkCandidates ?? [])),
    });
  }, [view, wikilinkCandidates]);

  // User extensions sync (full reconfigure on reference change).
  useEffect(() => {
    view?.dispatch({
      effects: userExtensionsCompartment.reconfigure([...userExtensions]),
    });
  }, [view, userExtensions]);

  return { view, setContainer };
}

import { useImperativeHandle, useMemo, type Ref } from "react";
import { undo as cmUndo, redo as cmRedo } from "@codemirror/commands";
import type { EditorView } from "@codemirror/view";
import { insertText as insertTextAction } from "../lib/toolbar-actions";
import type { MarkdownEditorHandle } from "../types";

interface UseHandleOpts {
  ref: Ref<MarkdownEditorHandle> | undefined;
  view: EditorView | null;
}

const DEV = process.env.NODE_ENV !== "production";
let warnedGetViewBeforeMount = false;

export function useMarkdownEditorHandle({ ref, view }: UseHandleOpts): void {
  const handle = useMemo<MarkdownEditorHandle>(
    () => ({
      focus() {
        view?.focus();
      },
      undo() {
        if (!view) return;
        cmUndo(view);
      },
      redo() {
        if (!view) return;
        cmRedo(view);
      },
      insertText(text: string) {
        if (!view) return;
        insertTextAction(view, text);
      },
      getSelection() {
        if (!view) return { from: 0, to: 0, text: "" };
        const { from, to } = view.state.selection.main;
        return { from, to, text: view.state.sliceDoc(from, to) };
      },
      getValue() {
        return view?.state.doc.toString() ?? "";
      },
      getView() {
        if (!view && DEV && !warnedGetViewBeforeMount) {
          warnedGetViewBeforeMount = true;
          console.warn(
            "[markdown-editor] getView() called before mount or after unmount; returned null.",
          );
        }
        return view;
      },
    }),
    [view],
  );

  useImperativeHandle(ref, () => handle, [handle]);
}

import { useState, useSyncExternalStore } from "react";

// External store: tracks a CM6-update counter so toolbar buttons re-render only when
// CM6 fires a relevant update (selection-change or doc-change), not on every keystroke
// at the React level (plan §4.4).
export interface ToolbarStore {
  subscribe: (cb: () => void) => () => void;
  getSnapshot: () => number;
  notify: () => void;
}

export function createToolbarStore(): ToolbarStore {
  let version = 0;
  const listeners = new Set<() => void>();
  return {
    subscribe(cb) {
      listeners.add(cb);
      return () => {
        listeners.delete(cb);
      };
    },
    getSnapshot() {
      return version;
    },
    notify() {
      version++;
      listeners.forEach((cb) => cb());
    },
  };
}

export function useToolbarStore(): ToolbarStore {
  const [store] = useState(createToolbarStore);
  return store;
}

export function useToolbarVersion(store: ToolbarStore): number {
  return useSyncExternalStore(store.subscribe, store.getSnapshot, store.getSnapshot);
}

import { useCallback, useState } from "react";
import type { ViewMode } from "../types";

interface UseViewModeOpts {
  view: ViewMode | undefined;
  onViewChange: ((view: ViewMode) => void) | undefined;
  initialView: ViewMode;
  showPreviewToggle: boolean;
}

interface UseViewModeResult {
  viewValue: ViewMode;
  handleViewChange: (next: ViewMode) => void;
  toggleHidden: boolean;
}

// Controlled-or-uncontrolled view-mode dispatch (plan §4.3).
// When showPreviewToggle is false, view is locked to initialView (toggle is hidden too).
export function useViewMode(opts: UseViewModeOpts): UseViewModeResult {
  const { view, onViewChange, initialView, showPreviewToggle } = opts;
  const isControlled = view !== undefined;
  const [internalView, setInternalView] = useState<ViewMode>(initialView);

  const lockedView = !showPreviewToggle ? initialView : null;
  const viewValue = lockedView ?? (isControlled ? view : internalView);

  const handleViewChange = useCallback(
    (next: ViewMode) => {
      if (lockedView) return;
      if (!isControlled) setInternalView(next);
      onViewChange?.(next);
    },
    [isControlled, lockedView, onViewChange],
  );

  return { viewValue, handleViewChange, toggleHidden: !showPreviewToggle };
}

import { Marked, type Tokens } from "marked";
import type { KindMeta, WikilinkCandidate } from "../types";

interface WikilinkToken extends Tokens.Generic {
  type: "wikilink";
  raw: string;
  label: string;
  alias: string | undefined;
}

const wikilinkExtension = {
  extensions: [
    {
      name: "wikilink",
      level: "inline" as const,
      start: (src: string) => src.indexOf("[["),
      tokenizer(src: string): WikilinkToken | undefined {
        const match = src.match(/^\[\[([^[\]\n|]+?)(?:\|([^[\]\n]+?))?\]\]/);
        if (!match) return undefined;
        return {
          type: "wikilink",
          raw: match[0],
          label: match[1].trim(),
          alias: match[2]?.trim(),
        };
      },
      renderer(token: WikilinkToken): string {
        const display = token.alias ?? token.label;
        return `<span class="wikilink" data-wikilink-target="${escapeHtml(token.label)}">${escapeHtml(display)}</span>`;
      },
    },
  ],
};

// Per-instance Marked (Q-P1 lock + validate-pass refinement #1) — avoids global
// `marked.use(...)` mutation that would pollute every other consumer of `marked`
// in the same bundle (e.g., the docs-site README parser).
const customMarked = new Marked();
customMarked.use({ gfm: true, breaks: false }, wikilinkExtension);

interface ParseOpts {
  wikilinkCandidates?: ReadonlyArray<WikilinkCandidate>;
  // kinds is part of the parse opts for forward-compat with kind-aware preview rendering;
  // unused in v0.1 (autocomplete renders kind badges, not preview).
  kinds?: Record<string, KindMeta>;
  hasClickHandler: boolean;
}

const WIKILINK_SPAN_REGEX = /<span class="wikilink" data-wikilink-target="([^"]+)">/g;

export function parseMarkdown(source: string, opts: ParseOpts): string {
  const html = customMarked.parse(source, { async: false }) as string;

  // Post-process: mark broken wikilinks; conditionally add role+tabindex when interactive
  // (validate-pass refinement #4 — only marked interactive when host wires onWikilinkClick).
  const interactive = opts.hasClickHandler;

  if (!opts.wikilinkCandidates) {
    return interactive
      ? html.replace(
          WIKILINK_SPAN_REGEX,
          (_, target) =>
            `<span class="wikilink" role="link" tabindex="0" data-wikilink-target="${target}">`,
        )
      : html;
  }

  const labelSet = new Set(opts.wikilinkCandidates.map((c) => c.label.toLowerCase().trim()));

  return html.replace(WIKILINK_SPAN_REGEX, (_, target) => {
    const resolved = labelSet.has(String(target).toLowerCase().trim());
    const classes = `wikilink${resolved ? "" : " wikilink-broken"}`;
    const roleAttr = interactive ? ' role="link" tabindex="0"' : "";
    return `<span class="${classes}"${roleAttr} data-wikilink-target="${target}">`;
  });
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (ch) => {
    switch (ch) {
      case "&":
        return "&amp;";
      case "<":
        return "&lt;";
      case ">":
        return "&gt;";
      case '"':
        return "&quot;";
      case "'":
        return "&#39;";
      default:
        return ch;
    }
  });
}

