import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import type { ToolbarCtx, ToolbarItem } from "../types";

interface ToolbarButtonProps {
  item: ToolbarItem;
  ctx: ToolbarCtx;
  disabled?: boolean;
}

export function ToolbarButton({ item, ctx, disabled }: ToolbarButtonProps) {
  const isActive = item.isActive ? item.isActive(ctx) : false;
  const tooltipLabel = item.shortcut ? `${item.label} (${item.shortcut})` : item.label;

  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          type="button"
          variant="ghost"
          size="icon-sm"
          aria-label={item.label}
          aria-pressed={item.isActive ? isActive : undefined}
          aria-keyshortcuts={item.shortcut}
          disabled={disabled}
          onClick={() => item.run(ctx)}
          className={cn(
            "text-muted-foreground hover:text-foreground",
            isActive && "bg-muted text-foreground",
          )}
        >
          {item.icon}
        </Button>
      </TooltipTrigger>
      <TooltipContent>{tooltipLabel}</TooltipContent>
    </Tooltip>
  );
}

import { ToolbarButton } from "./toolbar-button";
import { cn } from "@/lib/utils";
import type { ToolbarCtx, ToolbarItem } from "../types";

interface ToolbarProps {
  items: ReadonlyArray<ToolbarItem>;
  ctx: ToolbarCtx;
  disabled?: boolean;
  className?: string;
}

function isSeparator(item: ToolbarItem): boolean {
  return item.id.startsWith("sep");
}

export function Toolbar({ items, ctx, disabled, className }: ToolbarProps) {
  return (
    <div
      role="toolbar"
      aria-label="Markdown editor toolbar"
      className={cn(
        "flex flex-wrap items-center gap-1 rounded-t-md border border-b-0 border-border bg-card px-2 py-1.5",
        className,
      )}
    >
      {items.map((item) =>
        isSeparator(item) ? (
          <span
            key={item.id}
            aria-hidden
            className="mx-1 inline-block h-5 w-px bg-border"
          />
        ) : (
          <ToolbarButton key={item.id} item={item} ctx={ctx} disabled={disabled} />
        ),
      )}
    </div>
  );
}

import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";
import type { ViewMode } from "../types";

interface ViewToggleProps {
  value: ViewMode;
  onChange: (next: ViewMode) => void;
  className?: string;
}

export function ViewToggle({ value, onChange, className }: ViewToggleProps) {
  return (
    <Tabs
      value={value}
