        <TabsTrigger value="split" className="px-2 text-xs">
          Split
        </TabsTrigger>
        <TabsTrigger value="preview" className="px-2 text-xs">
          Preview
        </TabsTrigger>
      </TabsList>
    </Tabs>
  );
}
